                    if 0<=nr<h and 0<=nc<w and not visited[nr][nc] and grid[nr][nc]==color:
                        visited[nr][nc]=True
                        q.append((nr,nc))
            # bounding box
            rows=[r for r,c in cells]; cols=[c for r,c in cells]
            minr,maxr=min(rows),max(rows)
            minc,maxc=min(cols),max(cols)
            blobs.append({
                'color':color,
                'cells':cells,
                'touch':touches_border,
                'minr':minr,
                'maxr':maxr,
                'minc':minc,
                'maxc':maxc
            })
