def find_candidate(grid,color):
    # find horizontal segments length>1
    segsH=[]
    for r in range(grid.shape[0]):
        c=0
        while c<grid.shape[1]:
            if grid[r,c]==color:
                start=c
                while c<grid.shape[1] and grid[r,c]==color:
                    c+=1
                end=c-1
                if end-start+1>1:
                    segsH.append((r,start,end))
            else:
                c+=1
    # vertical segments
    segsV=[]
    for c in range(grid.shape[1]):
        r=0
        while r<grid.shape[0]:
            if grid[r,c]==color:
                start=r
                while r<grid.shape[0] and grid[r,c]==color:
                    r+=1
                end=r-1
                if end-start+1>1:
                    segsV.append((c,start,end))
            else:
                r+=1
    # Check for intersection
    for (rh, sh, eh) in segsH:
        for (cv, sv, ev) in segsV:
            if (rh>=sv and rh<=ev) and (cv>=sh and cv<=eh):
                return True, (rh, sh, eh, cv, sv, ev)
    return False, None
for col in [3,4]:
    print(col, find_candidate(test,col))

def count_segments(grid,color):
    h=0
    v=0
    for r in range(grid.shape[0]):
        length=0
        for c in range(grid.shape[1]):
            if grid[r,c]==color:
                length+=1
            else:
                if length>1:
                    h+=1
                length=0
        if length>1:
            h+=1
    for c in range(grid.shape[1]):
        length=0
        for r in range(grid.shape[0]):
            if grid[r,c]==color:
                length+=1
            else:
                if length>1:
                    v+=1
                length=0
        if length>1:
            v+=1
    return h,v
for col in [3,4]:
    print(col, count_segments(test,col))

def segments_counts(grid):
    res={}
    for c in np.unique(grid):
        if c==0: continue
        res[c]=count_segments(grid,c)
    return res
